const fs = await import('fs');
const path = await import('path');
const { pathToFileURL } = await import('url');
const candidates = [];
const home = process.env.HOME || '';
candidates.push(path.resolve(process.cwd(), 'plugins/revela/mcp/revela-server.ts'));
const configPath = path.join(home, '.codex', 'config.toml');
if (fs.existsSync(configPath)) {
  const text = fs.readFileSync(configPath, 'utf-8');
  const section = text.split(/\n(?=\s*\[)/).find((item) => item.trimStart().startsWith('[marketplaces.revela-local]'));
  const match = section?.match(/^\s*source\s*=\s*"([^"]+)"/m);
  if (match) candidates.push(path.join(match[1], 'plugins/revela/mcp/revela-server.ts'));
}
const cacheRoot = path.join(home, '.codex', 'plugins', 'cache', 'revela-local', 'revela');
if (fs.existsSync(cacheRoot)) {
  for (const version of fs.readdirSync(cacheRoot).sort().reverse()) candidates.push(path.join(cacheRoot, version, 'mcp/revela-server.ts'));
}
const server = candidates.find((candidate) => fs.existsSync(candidate));
if (!server) {
  console.error(`Could not locate Revela MCP server. Checked: ${candidates.join(', ')}`);
  process.exit(1);
}
await import(pathToFileURL(server).href);
